import React, { createContext, useCallback, useEffect, useMemo, useState } from 'react';
import { formatCurrency } from '../utils/helpers';
import type { Product } from '../utils/api';

export type CartItem = {
  id: string;
  name: string;
  price: number;
  image: string;
  quantity: number;
  size?: string;
  color?: string;
};

export type CartState = {
  items: CartItem[];
  isOpen: boolean;
};

type CartContextType = {
  items: CartItem[];
  isOpen: boolean;
  addToCart: (product: Product, opts?: { quantity?: number; size?: string; color?: string }) => void;
  removeFromCart: (key: string) => void;
  updateQuantity: (key: string, quantity: number) => void;
  increment: (key: string) => void;
  decrement: (key: string) => void;
  clearCart: () => void;
  openCart: () => void;
  closeCart: () => void;
  toggleCart: () => void;
  getCartCount: () => number;
  getCartTotal: () => number;
  getCartTotalFormatted: () => string;
  getKeyForItem: (item: { id: string; size?: string; color?: string }) => string;
};

const CartContext = createContext<CartContextType>({} as CartContextType);

const STORAGE_KEY = 'app_cart_state_v1';

const getKeyForItem = (item: { id: string; size?: string; color?: string }) => {
  const s = item.size ? `_${item.size}` : '';
  const c = item.color ? `_${item.color}` : '';
  return `${item.id}${s}${c}`;
};

export const CartProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [items, setItems] = useState<CartItem[]>([]);
  const [isOpen, setIsOpen] = useState<boolean>(false);

  useEffect(() => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const parsed: CartState = JSON.parse(raw);
        if (Array.isArray(parsed.items)) {
          setItems(parsed.items);
        }
        if (typeof parsed.isOpen === 'boolean') {
          setIsOpen(parsed.isOpen);
        }
      }
    } catch {
      // ignore
    }
  }, []);

  useEffect(() => {
    const state: CartState = { items, isOpen };
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
    } catch {
      // ignore
    }
  }, [items, isOpen]);

  const addToCart = useCallback((product: Product, opts?: { quantity?: number; size?: string; color?: string }) => {
    const quantity = Math.max(1, opts?.quantity ?? 1);
    const size = opts?.size;
    const color = opts?.color;
    const key = getKeyForItem({ id: product.id, size, color });

    setItems(prev => {
      const existingIndex = prev.findIndex(i => getKeyForItem(i) === key);
      if (existingIndex >= 0) {
        const next = [...prev];
        next[existingIndex] = { ...next[existingIndex], quantity: next[existingIndex].quantity + quantity };
        return next;
      }
      const image = product.images?.[0] ?? '';
      return [
        ...prev,
        {
          id: product.id,
          name: product.name,
          price: product.price,
          image,
          quantity,
          size,
          color,
        },
      ];
    });
    setIsOpen(true);
  }, []);

  const removeFromCart = useCallback((key: string) => {
    setItems(prev => prev.filter(i => getKeyForItem(i) !== key));
  }, []);

  const updateQuantity = useCallback((key: string, quantity: number) => {
    const q = Math.max(1, quantity);
    setItems(prev => prev.map(i => (getKeyForItem(i) === key ? { ...i, quantity: q } : i)));
  }, []);

  const increment = useCallback((key: string) => {
    setItems(prev => prev.map(i => (getKeyForItem(i) === key ? { ...i, quantity: i.quantity + 1 } : i)));
  }, []);

  const decrement = useCallback((key: string) => {
    setItems(prev => prev.map(i => (getKeyForItem(i) === key ? { ...i, quantity: Math.max(1, i.quantity - 1) } : i)));
  }, []);

  const clearCart = useCallback(() => {
    setItems([]);
  }, []);

  const openCart = useCallback(() => setIsOpen(true), []);
  const closeCart = useCallback(() => setIsOpen(false), []);
  const toggleCart = useCallback(() => setIsOpen(prev => !prev), []);

  const getCartCount = useCallback(() => items.reduce((acc, i) => acc + i.quantity, 0), [items]);
  const getCartTotal = useCallback(() => items.reduce((acc, i) => acc + i.price * i.quantity, 0), [items]);
  const getCartTotalFormatted = useCallback(() => formatCurrency(getCartTotal()), [getCartTotal]);

  const value = useMemo<CartContextType>(() => ({
    items,
    isOpen,
    addToCart,
    removeFromCart,
    updateQuantity,
    increment,
    decrement,
    clearCart,
    openCart,
    closeCart,
    toggleCart,
    getCartCount,
    getCartTotal,
    getCartTotalFormatted,
    getKeyForItem,
  }), [items, isOpen, addToCart, removeFromCart, updateQuantity, increment, decrement, clearCart, openCart, closeCart, toggleCart, getCartCount, getCartTotal, getCartTotalFormatted]);

  return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
};

const useCart = () => React.useContext(CartContext);

export default useCart;

