import React, { createContext, useCallback, useEffect, useMemo, useState } from 'react';
import {
  getCategories,
  getFeaturedProducts,
  getProduct,
  getProducts,
  getTrendingProducts,
  searchProducts,
} from '../utils/api';
import type { Product } from '../utils/api';

export type ProductFilters = {
  search: string;
  category: string | 'all';
  minPrice?: number;
  maxPrice?: number;
  sort:
    | 'relevance'
    | 'price-asc'
    | 'price-desc'
    | 'rating-desc'
    | 'newest'
    | 'popular';
};

type ProductContextType = {
  products: Product[];
  filtered: Product[];
  categories: string[];
  featured: Product[];
  trending: Product[];
  loading: boolean;
  filters: ProductFilters;
  setFilter: (patch: Partial<ProductFilters>) => void;
  resetFilters: () => void;
  toggleFavorite: (id: string) => void;
  favorites: Set<string>;
  getProductById: (id: string) => Promise<Product | undefined>;
  refresh: () => void;
};

const ProductContext = createContext<ProductContextType>({} as ProductContextType);

const DEFAULT_FILTERS: ProductFilters = {
  search: '',
  category: 'all',
  minPrice: undefined,
  maxPrice: undefined,
  sort: 'relevance',
};

const FAV_KEY = 'app_favorites_v1';

export const ProductProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<string[]>([]);
  const [featured, setFeatured] = useState<Product[]>([]);
  const [trending, setTrending] = useState<Product[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [filters, setFilters] = useState<ProductFilters>(DEFAULT_FILTERS);
  const [favorites, setFavorites] = useState<Set<string>>(() => {
    try {
      const raw = localStorage.getItem(FAV_KEY);
      if (!raw) return new Set<string>();
      const arr: string[] = JSON.parse(raw);
      return new Set<string>(arr);
    } catch {
      return new Set<string>();
    }
  });

  const load = useCallback(async () => {
    setLoading(true);
    const [p, c, f, t] = await Promise.all([
      getProducts(),
      getCategories(),
      getFeaturedProducts(),
      getTrendingProducts(),
    ]);
    setProducts(p);
    setCategories(['all', ...c]);
    setFeatured(f);
    setTrending(t);
    setLoading(false);
  }, []);

  useEffect(() => {
    load();
  }, [load]);

  useEffect(() => {
    try {
      localStorage.setItem(FAV_KEY, JSON.stringify(Array.from(favorites)));
    } catch {
      // ignore
    }
  }, [favorites]);

  const setFilter = useCallback((patch: Partial<ProductFilters>) => {
    setFilters(prev => ({ ...prev, ...patch }));
  }, []);

  const resetFilters = useCallback(() => setFilters(DEFAULT_FILTERS), []);

  const toggleFavorite = useCallback((id: string) => {
    setFavorites(prev => {
      const next = new Set(prev);
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  }, []);

  const getProductById = useCallback(async (id: string) => {
    const local = products.find(p => p.id === id);
    if (local) return local;
    return getProduct(id);
  }, [products]);

  const filtered = useMemo(() => {
    let list = [...products];

    if (filters.search.trim().length > 0) {
      const q = filters.search.trim();
      list = searchProducts(q, list);
    }

    if (filters.category && filters.category !== 'all') {
      list = list.filter(p => p.category.toLowerCase() === filters.category.toLowerCase());
    }

    if (typeof filters.minPrice === 'number') {
      list = list.filter(p => p.price >= (filters.minPrice as number));
    }

    if (typeof filters.maxPrice === 'number') {
      list = list.filter(p => p.price <= (filters.maxPrice as number));
    }

    switch (filters.sort) {
      case 'price-asc':
        list.sort((a, b) => a.price - b.price);
        break;
      case 'price-desc':
        list.sort((a, b) => b.price - a.price);
        break;
      case 'rating-desc':
        list.sort((a, b) => b.rating - a.rating);
        break;
      case 'newest':
        list.sort((a, b) => Number(b.newArrival) - Number(a.newArrival));
        break;
      case 'popular':
        list.sort((a, b) => b.reviews - a.reviews);
        break;
      default:
        break;
    }

    return list;
  }, [products, filters]);

  const refresh = useCallback(() => {
    load();
  }, [load]);

  const value: ProductContextType = {
    products,
    filtered,
    categories,
    featured,
    trending,
    loading,
    filters,
    setFilter,
    resetFilters,
    toggleFavorite,
    favorites,
    getProductById,
    refresh,
  };

  return <ProductContext.Provider value={value}>{children}</ProductContext.Provider>;
};

const useProducts = () => React.useContext(ProductContext);

export default useProducts;

