const buildCategories = (list: Product[]) => {
  const c = Array.from(new Set(list.map(p => p.category)));
  c.sort((a, b) => a.localeCompare(b));
  return c;
};

export const getProducts = async (): Promise<Product[]> => {
  if (!cache.products) {
    cache.products = productsSeed;
  }
  return simulateNetwork(cache.products);
};

export const getProduct = async (id: string): Promise<Product | undefined> => {
  const list = await getProducts();
  return simulateNetwork(list.find(p => p.id === id));
};

export const getCategories = async (): Promise<string[]> => {
  if (!cache.categories) {
    const list = await getProducts();
    cache.categories = buildCategories(list);
  }
  return simulateNetwork(cache.categories);
};

export const getFeaturedProducts = async (): Promise<Product[]> => {
  if (!cache.featured) {
    const list = await getProducts();
    cache.featured = list.filter(p => p.featured || p.newArrival).slice(0, 6);
  }
  return simulateNetwork(cache.featured);
};

export const getTrendingProducts = async (): Promise<Product[]> => {
  if (!cache.trending) {
    const list = await getProducts();
    cache.trending = [...list].sort((a, b) => b.reviews - a.reviews).slice(0, 6);
  }
  return simulateNetwork(cache.trending);
};

export const searchProducts = (query: string, source?: Product[]): Product[] => {
  const q = query.trim().toLowerCase();
  const list = source ?? (cache.products ?? productsSeed);
  if (!q) return list;
  return list.filter(p => {
    const hay = [
      p.name,
      p.description,
      p.category,
      ...(p.tags ?? []),
      ...(p.colors ?? []),
    ]
      .join(' ')
      .toLowerCase();
    return hay.includes(q);
  });
};

export const getRecommended = async (productId: string): Promise<Product[]> => {
  const list = await getProducts();
  const base = list.find(p => p.id === productId);
  if (!base) return simulateNetwork(list.slice(0, 4));
  const rec = list
    .filter(p => p.id !== base.id && (p.category === base.category || p.tags?.some(t => base.tags?.includes(t) || base.colors?.some(c => t.toLowerCase().includes(c.toLowerCase())))))
    .slice(0, 6);
  return simulateNetwork(rec.length ? rec : list.filter(p => p.id !== base.id).slice(0, 6));
};

